"use strict";

/** Normalize answer text exactly as the publisher did. */
function normalizePublishedAnswer(value) {
  return String(value)
    .normalize("NFKC")
    .trim()
    .replace(/\s+/g, " ")
    .toLowerCase();
}

/** Return the lowercase SHA-256 hex digest used by aHash. */
async function hashPublishedAnswer(value) {
  const bytes = new TextEncoder().encode(normalizePublishedAnswer(value));
  const digest = await crypto.subtle.digest("SHA-256", bytes);
  return Array.from(new Uint8Array(digest), byte => byte.toString(16).padStart(2, "0")).join("");
}

/** Check selected option text against a published question record. */
async function isPublishedAnswerCorrect(question, selectedOptionText) {
  if (!question || typeof question.aHash !== "string") return false;
  return (await hashPublishedAnswer(selectedOptionText)) === question.aHash;
}

